import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';

function Navbar() {
  const [scrolled, setScrolled] = useState(false);
  const location = useLocation();

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 50);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <nav style={{
      position: 'fixed', top: 0, width: '100%', zIndex: 1000,
      background: scrolled ? 'rgba(0,0,0,0.97)' : 'rgba(0,0,0,0.7)',
      borderBottom: scrolled ? '2px solid #00aa00' : '1px solid rgba(0,170,0,0.3)',
      display: 'flex', justifyContent: 'space-between',
      alignItems: 'center', padding: '10px 50px',
      transition: 'all 0.4s ease',
      boxShadow: scrolled ? '0 0 20px rgba(0,170,0,0.3)' : 'none'
    }}>
      <Link to="/" style={{ display: 'flex', alignItems: 'center', gap: '12px', textDecoration: 'none' }}>
        <img src="/logo.png" alt="BBRS Morphix IT" style={{ width: '55px', height: '55px', borderRadius: '50%', border: '2px solid #00aa00' }} />
        <span style={{ color: '#ffd700', fontSize: '20px', fontWeight: 'bold', letterSpacing: '2px' }}>BBRS Morphix IT</span>
      </Link>
      <ul style={{ display: 'flex', gap: '30px', listStyle: 'none', margin: 0, padding: 0 }}>
        {[['/', 'Accueil'],['/services','Services'],['/apropos','À propos'],['/blog','Blog'],['/contact','Contact']].map(([path, label]) => (
          <li key={path}>
            <Link to={path} style={{
              color: location.pathname === path ? '#00aa00' : '#ffffff',
              textDecoration: 'none', fontSize: '15px',
              borderBottom: location.pathname === path ? '2px solid #00aa00' : '2px solid transparent',
              paddingBottom: '3px', transition: 'all 0.3s',
              fontWeight: location.pathname === path ? 'bold' : 'normal'
            }}>{label}</Link>
          </li>
        ))}
      </ul>
    </nav>
  );
}

export default Navbar;
